import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

// --- Utils ---
function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

// --- Components ---

const NoiseOverlay = () => (
  <div className="fixed inset-0 pointer-events-none z-50 opacity-[0.03] mix-blend-overlay">
    <svg className="w-full h-full">
      <filter id="noiseFilter">
        <feTurbulence type="fractalNoise" baseFrequency="0.6" numOctaves="3" stitchTiles="stitch" />
      </filter>
      <rect width="100%" height="100%" filter="url(#noiseFilter)" />
    </svg>
  </div>
);

const RevealText = ({ children, delay = 0, className }: { children: React.ReactNode; delay?: number; className?: string }) => {
  return (
    <div className={cn("overflow-hidden inline-block align-bottom", className)}>
      <motion.span
        initial={{ y: "110%" }}
        whileInView={{ y: 0 }}
        transition={{ duration: 1, ease: [0.16, 1, 0.3, 1], delay }}
        viewport={{ once: true }}
        className="block"
      >
        {children}
      </motion.span>
    </div>
  );
};

const MagneticButton = ({ children, className, onClick }: { children: React.ReactNode; className?: string; onClick?: () => void }) => {
  return (
    <motion.button
      className={cn("relative overflow-hidden group", className)}
      whileHover="hover"
      onClick={onClick}
    >
      <motion.div
        className="absolute inset-0 bg-blue-600 translate-y-full"
        variants={{
          hover: { translateY: 0 }
        }}
        transition={{ duration: 0.3, ease: "easeInOut" }}
      />
      <span className="relative z-10 group-hover:text-white transition-colors duration-300">{children}</span>
    </motion.button>
  );
};

const ParallaxImage = ({ src, alt, speed = 0.1, className }: { src: string; alt: string; speed?: number; className?: string }) => {
  const ref = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({
    target: ref,
    offset: ["start end", "end start"]
  });

  const y = useTransform(scrollYProgress, [0, 1], ["-10%", "10%"]);

  return (
    <div ref={ref} className={cn("overflow-hidden h-full w-full relative", className)}>
      <motion.img 
        style={{ y }}
        src={src} 
        alt={alt} 
        className="w-full h-[120%] object-cover object-center absolute -top-[10%]"
      />
    </div>
  );
};

const Marquee = ({ children, direction = 1 }: { children: React.ReactNode; direction?: number }) => {
  return (
    <div className="overflow-hidden whitespace-nowrap flex select-none py-8 border-y border-stone-300 bg-stone-100">
      <motion.div
        className="flex min-w-full gap-16 items-center"
        animate={{ x: direction > 0 ? ["0%", "-50%"] : ["-50%", "0%"] }}
        transition={{ repeat: Infinity, ease: "linear", duration: 25 }}
      >
        {children}
        {children}
        {children}
        {children}
      </motion.div>
    </div>
  );
};

