const TextReveal = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start end", "end start"]
  });

  const text = "Abolishing the gap between creative intent and digital reality through a masterfully orchestrated symphony of neural design intelligence.";
  const words = text.split(" ");

  return (
    <section ref={containerRef} className="py-40 md:py-64 bg-background border-y border-border relative overflow-hidden">
      <div className="container mx-auto px-4 max-w-5xl text-center">
        <div className="flex flex-wrap justify-center gap-x-4 gap-y-2">
          {words.map((word, i) => {
            const start = i / words.length;
            const end = (i + 1) / words.length;
            const opacity = useTransform(scrollYProgress, [start * 0.4 + 0.1, end * 0.4 + 0.1], [0.15, 1]);

            return (
              <motion.span 
                key={i} 
                style={{ opacity }}
                className="text-3xl md:text-6xl font-serif font-light tracking-tight text-foreground"
              >
                {word}
              </motion.span>
            );
          })}
        </div>
      </div>
    </section>
  );
};

