  return (
    <div className="relative w-full h-screen bg-black">
      <PrismBackground
        animationType="hover"
        glow={1.2}
        hueShift={0.5}
        scale={4}
        suspendWhenOffscreen={true}
      />
      <div className="relative z-10 text-white">
        Your content here
      </div>
    </div>
  );
}
