            effectAmplitude={1.5}
            backgroundColor={[0, 0, 0, 0]}
          />
        </div>

        {/* Content Overlay */}
        <div className="absolute inset-0 z-10 flex flex-col items-center justify-center pointer-events-none p-12 text-center">
          <motion.h1 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
